const items = $input.all();
return items.map((item) => {
  let insight = 'AI analysis unavailable';
  let priority = 'NEW';
  try {
    const content = item.json.choices[0].message.content;
    const parsed = JSON.parse(content);
    if (parsed.insight) insight = parsed.insight;
    if (['NEW', 'CONTACTED', 'QUALIFIED'].includes(parsed.priority)) priority = parsed.priority;
  } catch (e) {
    // keep fallback values
  }
  return {
    json: {
      leadId: $('Normalize Lead').item.json.leadId,
      name: $('Normalize Lead').item.json.name,
      email: $('Normalize Lead').item.json.email,
      aiInsight: insight,
      priority,
    },
  };
});

