const items = $input.all();
return items.map((item) => {
  let reply = 'Let me get a team member to help with that.';
  let escalate = true;
  try {
    const content = item.json.choices[0].message.content;
    const parsed = JSON.parse(content);
    if (parsed.reply) reply = parsed.reply;
    if (typeof parsed.escalate === 'boolean') escalate = parsed.escalate;
  } catch (e) {
    // keep fallback (escalate = true)
  }
  return {
    json: {
      message: $('Normalize Chat').item.json.message,
      reply,
      escalate,
    },
  };
});

